export const scene: DialogueEntry[] = [
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "01:25。", background: Background.Chapter_8_Ch8_Act3_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "急診觀察區外。走廊盡頭。", background: Background.Chapter_8_Ch8_Act3_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "澪沒有坐回等候區。她站在走廊和等候區的交界處。牆上有一扇玻璃窗。窗的另一邊是觀察區。簾子。推床。監測儀。氧氣架。", background: Background.Chapter_8_Ch8_Act3_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "走廊深處傳來輪子聲。不是保管推車。是病床。有人在推床。", background: Background.Chapter_8_Ch8_Act3_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "她看見一張床被推出來。床上有個人。臉色灰白。氧氣面罩罩著半張臉。透明的面罩裡有霧氣。一進。一出。很淺。很慢。", background: Background.Chapter_8_Ch8_Act3_S0 },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "（內心）⋯⋯千田。", background: Background.Chapter_8_Ch8_Act3_S0, portrait: Portrait.AsakuraMio_Shocked },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "他被推過走廊。從處置區往觀察區的方向。兩個醫護跟在床邊。一個推床。一個調整點滴架。腳步很快。但沒有跑。", background: Background.Chapter_8_Ch8_Act3_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "澪站在玻璃窗這一側。隔著玻璃。隔著三公尺的走廊。她不能過去。黃線。門。流程。", background: Background.Chapter_8_Ch8_Act3_S0 },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "（內心）⋯⋯臉色比剛才更差。在簾子縫裡看的時候，胸口起伏還算清楚。現在——很淺。面罩的霧氣很淡。像快沒有力氣呼吸了。", background: Background.Chapter_8_Ch8_Act3_S0, portrait: Portrait.AsakuraMio_Scared },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "床推到觀察區入口。醫護停下來。其中一個彎腰調整面罩的管子。另一個低頭看監測儀。", background: Background.Chapter_8_Ch8_Act3_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "千田的眼睛開了。", background: Background.Chapter_8_Ch8_Act3_S0 },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "（內心）⋯⋯又醒了。", background: Background.Chapter_8_Ch8_Act3_S0, portrait: Portrait.AsakuraMio_Scared },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "不是完全睜開。是一條縫。像在剛才的處置區裡一樣。但這一次，他的視線好像落在了什麼地方。不是天花板。不是走廊盡頭。是——", background: Background.Chapter_8_Ch8_Act3_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "玻璃窗。她站的方向。", background: Background.Chapter_8_Ch8_Act3_S0 },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "（內心）⋯⋯他在看我。", background: Background.Chapter_8_Ch8_Act3_S0, portrait: Portrait.AsakuraMio_Shocked },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "她不確定。隔著玻璃。隔著三公尺。隔著氧氣面罩的霧氣。他可能在看她。可能在看玻璃。可能在看玻璃後面的牆。她不知道。", background: Background.Chapter_8_Ch8_Act3_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "但她的嘴動了。", background: Background.Chapter_8_Ch8_Act3_S0 },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "⋯⋯袋子——", background: Background.Chapter_8_Ch8_Act3_S0, portrait: Portrait.AsakuraMio_Base },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "沒有聲音。玻璃隔著。她說了兩個字。嘴型。只有嘴型。", background: Background.Chapter_8_Ch8_Act3_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "她下意識想問「袋子呢」。想問「外殼呢」。但聲音被玻璃擋住了。也許這樣更好。也許她不應該在這裡喊。", background: Background.Chapter_8_Ch8_Act3_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "一名護士抬起頭。看見她站在玻璃窗那一側。", background: Background.Chapter_8_Ch8_Act3_S0 },
    { characterId: CharacterId.MedicalStaff, character: "醫護", dialogue: "請不要站在這裡。請到觀察區外面等候。", background: Background.Chapter_8_Ch8_Act3_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "語氣不凶。像在提醒。像在說「這裡不是妳該待的地方」。", background: Background.Chapter_8_Ch8_Act3_S0 },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "⋯⋯好。", background: Background.Chapter_8_Ch8_Act3_S0, portrait: Portrait.AsakuraMio_Base },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "她沒有退。還沒有。因為千田的手動了。", background: Background.Chapter_8_Ch8_Act3_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "他的右手。放在床單上。手指動了一下。不是握拳。不是指向什麼。是——抓。反覆地抓。指尖張開。合攏。張開。合攏。像在抓空氣裡一個看不見的東西。", background: Background.Chapter_8_Ch8_Act3_S0 },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "（內心）⋯⋯那個手勢。在處置區的時候也做過。手指在抓。像在找什麼。", background: Background.Chapter_8_Ch8_Act3_S0, portrait: Portrait.AsakuraMio_Scared },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "不是指向走廊。不是指向保安室的方向。是反覆抓空。像在找一片薄薄的東西。像手指之間應該夾著什麼，但什麼都沒有。", background: Background.Chapter_8_Ch8_Act3_S0 },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "（內心）⋯⋯薄片。他在找薄片。他知道——他知道那個東西不在他身上了。", background: Background.Chapter_8_Ch8_Act3_S0, portrait: Portrait.AsakuraMio_Scared },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "醫護低頭看了一眼他的手。沒有特別反應。像在看一個疼痛反射。像在看一個無意識動作。她記下了什麼。然後繼續調整點滴。", background: Background.Chapter_8_Ch8_Act3_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "千田的嘴在動。面罩下面。聲音很小。隔著玻璃，澪幾乎聽不見。但她看見了嘴型。看見了喉嚨在用力。像在試著說什麼。", background: Background.Chapter_8_Ch8_Act3_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "然後她聽見了。不是因為聲音大。是因為走廊安靜。因為玻璃窗沒有完全關緊。因為觀察區的門開著一條縫。聲音從縫裡漏出來。破碎的。斷裂的。像被面罩和喉嚨裡的什麼東西絞碎了。", background: Background.Chapter_8_Ch8_Act3_S0 },
    { characterId: CharacterId.ChidaKosuke, character: "千田浩介", dialogue: "⋯⋯袋⋯⋯", background: Background.Chapter_8_Ch8_Act3_S0, portrait: Portrait.ChidaKosuke_Base },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "一個字。半個字。氣音。然後是咳嗽。面罩裡的霧氣亂了一瞬。", background: Background.Chapter_8_Ch8_Act3_S0 },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "（內心）⋯⋯袋。他說了「袋」。", background: Background.Chapter_8_Ch8_Act3_S0, portrait: Portrait.AsakuraMio_Shocked },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "千田的手又抓了一下。指尖合攏。空的。什麼都沒抓住。", background: Background.Chapter_8_Ch8_Act3_S0 },
    { characterId: CharacterId.ChidaKosuke, character: "千田浩介", dialogue: "⋯⋯不是⋯⋯裡面⋯⋯", background: Background.Chapter_8_Ch8_Act3_S0, portrait: Portrait.ChidaKosuke_Base },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "更破碎。像三個詞被拆開扔出來。沒有主詞。沒有動詞。沒有完整的句子。只有碎片。", background: Background.Chapter_8_Ch8_Act3_S0 },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "（內心）⋯⋯不是。裡面。不是什麼？裡面什麼？不是在裡面？還是——不對。他說不清楚。他說不清楚。", background: Background.Chapter_8_Ch8_Act3_S0, portrait: Portrait.AsakuraMio_Scared },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "醫護彎下腰。把手放在他的手背上。輕輕壓住。", background: Background.Chapter_8_Ch8_Act3_S0 },
    { characterId: CharacterId.MedicalStaff, character: "醫護", dialogue: "不要說話。先休息。", background: Background.Chapter_8_Ch8_Act3_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "千田的嘴還在動。但沒有聲音出來了。只有面罩裡的霧氣。一進。一出。更淺了。", background: Background.Chapter_8_Ch8_Act3_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "另一個醫護走過來。拉簾子。淺藍色的布簾。從床的兩側拉過來。一層一層。把千田的手、臉、氧氣面罩、監測儀——全部遮住。", background: Background.Chapter_8_Ch8_Act3_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "簾子合攏了。", background: Background.Chapter_8_Ch8_Act3_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "澪站在玻璃窗外面。手貼在玻璃上。她不知道什麼時候把手放上去的。指尖的溫度透過玻璃，被走廊的冷氣吸走了。", background: Background.Chapter_8_Ch8_Act3_S0 },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "（內心）⋯⋯袋。不是。裡面。三個碎片。沒有一句完整的話。沒有證詞。沒有可以寫進筆錄的東西。", background: Background.Chapter_8_Ch8_Act3_S0, portrait: Portrait.AsakuraMio_Sad },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "（內心）⋯⋯但他的手。那個手勢。反覆抓空。像在找一片薄薄的東西。那不是疼痛反射。疼痛反射不會那麼精準。不會反覆找同一個形狀。", background: Background.Chapter_8_Ch8_Act3_S0, portrait: Portrait.AsakuraMio_Sad },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "（內心）⋯⋯他知道。他知道那個東西不在了。他想告訴我。但他說不出來。面罩擋著。喉嚨沒有力氣。醫護在旁邊。沒有人能正式記錄他說的話。", background: Background.Chapter_8_Ch8_Act3_S0, portrait: Portrait.AsakuraMio_Sad },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "她把手從玻璃上拿下來。玻璃上留了兩個掌印。很快被冷氣吹乾了。消失了。", background: Background.Chapter_8_Ch8_Act3_S0 },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "（內心）⋯⋯他沒有留下證詞。他留下了一個手勢。一個會折磨我的手勢。", background: Background.Chapter_8_Ch8_Act3_S0, portrait: Portrait.AsakuraMio_Determined },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "簾子後面傳出監測儀的聲音。嗶。嗶。嗶。很規律。很安靜。", background: Background.Chapter_8_Ch8_Act3_S0 },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "（內心）⋯⋯每一次他可能醒來的時候，都剛好沒有可以聽見他的人。在處置區，我隔著簾子縫。在觀察區，我隔著玻璃。醫護在旁邊，但他們只聽見「疼痛反射」。", background: Background.Chapter_8_Ch8_Act3_S0, portrait: Portrait.AsakuraMio_Sad },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "（內心）⋯⋯不是沒有人。是沒有能正式記錄的人。是沒有被允許聽見的人。", background: Background.Chapter_8_Ch8_Act3_S0, portrait: Portrait.AsakuraMio_Sad },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "她退了一步。兩步。離開玻璃窗。走廊的燈照在她臉上。她看起來很疲倦。眼下有青黑色的影子。", background: Background.Chapter_8_Ch8_Act3_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "她從內袋摸出紙。攤開。用指甲壓。", background: Background.Chapter_8_Ch8_Act3_S0 },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "（內心）⋯⋯千田：短暫清醒。手勢：反覆抓空，像找薄片。聲音：袋。不是。裡面。無完整證詞。", background: Background.Chapter_8_Ch8_Act3_S0, portrait: Portrait.AsakuraMio_Determined },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "她壓完。把紙摺起來。塞回內袋。手指碰到小鏡子的布套。她握了一下。鬆開。", background: Background.Chapter_8_Ch8_Act3_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "簾子後面的監測儀還在響。嗶。嗶。嗶。", background: Background.Chapter_8_Ch8_Act3_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "她轉身。走回等候區的方向。", background: Background.Chapter_8_Ch8_Act3_S0 },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "（內心）⋯⋯病人物袋這條線，不是我想太多。千田本人也在意。他的手在找它。他的嘴在說它。但他說不出完整的句子。而我——隔著玻璃，連他的氣音都只能聽見一半。", background: Background.Chapter_8_Ch8_Act3_S0, portrait: Portrait.AsakuraMio_Sad },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "走廊很長。她的腳步聲很輕。簾子後面的聲音越來越遠。", background: Background.Chapter_8_Ch8_Act3_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "嗶。嗶。嗶。", background: Background.Chapter_8_Ch8_Act3_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "像在倒數。", background: Background.Chapter_8_Ch8_Act3_S0 },
];
